namespace sv_65156a18507946ea91b94115a55ce34e.Services;

/// <summary>
/// Scoped service that manages low-stock alert polling per circuit.
/// Each user circuit gets its own instance (isolated state).
/// </summary>
public class InventoryAlertService : IDisposable
{
    private readonly WarehouseState _warehouseState;
    private readonly Random _random = new();

    private Timer? _timer;
    private int _subscriberCount;
    private int _currentLowStockCount;

    public int LowStockCount => _currentLowStockCount;

    /// <summary>
    /// Fired when polling detects new data. All subscribed components should refresh.
    /// </summary>
    public event Action? OnAlertCountChanged;

    public InventoryAlertService(WarehouseState warehouseState)
    {
        _warehouseState = warehouseState;
        _warehouseState.OnChange += OnWarehouseChanged;
    }

    /// <summary>
    /// Simulates a database query returning low-stock item count.
    /// </summary>
    public Task<int> GetLowStockCountAsync(string warehouseId)
    {
        return Task.FromResult(_random.Next(0, 16));
    }

    /// <summary>
    /// Call when a component wants polling active. Polling starts on first subscriber.
    /// </summary>
    public void StartPolling()
    {
        _subscriberCount++;
        if (_subscriberCount == 1)
        {
            _timer = new Timer(PollCallback, null, TimeSpan.Zero, TimeSpan.FromSeconds(10));
        }
    }

    /// <summary>
    /// Call when a component no longer needs polling. Polling stops when no subscribers remain.
    /// </summary>
    public void StopPolling()
    {
        _subscriberCount = Math.Max(0, _subscriberCount - 1);
        if (_subscriberCount == 0)
        {
            _timer?.Dispose();
            _timer = null;
        }
    }

    private async void PollCallback(object? state)
    {
        var count = await GetLowStockCountAsync(_warehouseState.SelectedWarehouseId);
        _currentLowStockCount = count;
        OnAlertCountChanged?.Invoke();
    }

    private async void OnWarehouseChanged()
    {
        // Immediately refresh when warehouse changes
        if (_timer is not null)
        {
            var count = await GetLowStockCountAsync(_warehouseState.SelectedWarehouseId);
            _currentLowStockCount = count;
            OnAlertCountChanged?.Invoke();
        }
    }

    public void Dispose()
    {
        _warehouseState.OnChange -= OnWarehouseChanged;
        _timer?.Dispose();
    }
}

