@page "/dashboard"
@using sv_65156a18507946ea91b94115a55ce34e.Services
@inject WarehouseState WarehouseState
@inject InventoryAlertService AlertService
@implements IDisposable
@rendermode InteractiveServer

<PageTitle>Dashboard – @WarehouseState.SelectedWarehouseName</PageTitle>

<h1>Warehouse Dashboard</h1>
<p class="lead">Currently viewing: <strong>@WarehouseState.SelectedWarehouseName</strong></p>

<div class="row mt-4">
    <div class="col-md-4">
        <div class="card border-danger">
            <div class="card-body text-center">
                <h5 class="card-title text-danger">Low Stock Alerts</h5>
                <p class="display-4">@AlertService.LowStockCount</p>
                <p class="text-muted small">Items below minimum level (refreshes every 10s)</p>
            </div>
        </div>
    </div>
</div>

@code {
    private Action? _warehouseHandler;
    private Action? _alertHandler;

    protected override void OnInitialized()
    {
        _warehouseHandler = () => InvokeAsync(StateHasChanged);
        _alertHandler = () => InvokeAsync(StateHasChanged);

        WarehouseState.OnChange += _warehouseHandler;
        AlertService.OnAlertCountChanged += _alertHandler;

        // Start polling when dashboard is visible
        AlertService.StartPolling();
    }

    public void Dispose()
    {
        // Stop polling when user leaves the page
        AlertService.StopPolling();
        WarehouseState.OnChange -= _warehouseHandler;
        AlertService.OnAlertCountChanged -= _alertHandler;
    }
}

